(function (global) {
  var ns = (global.AppBackend = global.AppBackend || {});
  var TESTIMONIAL_IMAGES = ["img/57.jpg", "img/58.jpg", "img/59.jpg", "img/60.jpg", "img/35.jpg"];
  var SUPPORTED_VARIETIES = ["amelonado", "bresilien", "cundeamor", "forastero", "criollo", "trinitario"];
  var VOTE_STORAGE_PREFIX = "chococam:testimonial-vote:";
  function byId(id) {
    return document.getElementById(id);
  }
  function escapeHtml(value) {
    return String(value || "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }
  function normalizeVarietySlug(raw) {
    var slug = String(raw || "").toLowerCase().trim();
    if (SUPPORTED_VARIETIES.indexOf(slug) >= 0) {
      return slug;
    }
    return "";
  }
  function isUuid(value) {
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(value || ""));
  }
  function getActiveProductSlug() {
    var fileName = String((location.pathname.split("/").pop() || "")).toLowerCase();
    if (fileName.indexOf("product_") === 0) {
      var raw = fileName.replace("product_", "").replace(".html", "");
      if (raw && raw !== "detail") {
        return raw;
      }
    }
    var params = new URLSearchParams(location.search);
    var fromQuery = normalizeVarietySlug(params.get("variety"));
    return fromQuery || "forastero";
  }
  function safeInt(value) {
    var n = Number(value);
    if (!isFinite(n)) return 0;
    return Math.max(0, Math.floor(n));
  }
  function formatDate(value) {
    if (!value) return "";
    var dt = new Date(value);
    if (isNaN(dt.getTime())) return "";
    try {
      return dt.toLocaleDateString("en-US", { month: "short", day: "2-digit", year: "numeric" });
    } catch (error) {
      return dt.toDateString();
    }
  }
  function starIcons(rating) {
    var safeRating = Math.max(1, Math.min(5, Math.round(Number(rating || 5))));
    var stars = "";
    for (var i = 1; i <= 5; i += 1) {
      stars += '<i class="fa ' + (i <= safeRating ? "fa-star" : "fa-star-o") + '" aria-hidden="true"></i>';
    }
    return stars;
  }
  function getFallbackTestimonials(slug) {
    var base = [
      {
        id: "fallback-1",
        author_name: "Procurement Lead",
        author_title: "EU Chocolate Group",
        author_country: "Belgium",
        message: "Documentation quality is excellent and shipment schedules are consistently respected. Their export desk communicates clearly from loading to arrival.",
        rating: 5,
        up_votes: 8,
        down_votes: 0,
        created_at: "2026-01-14T00:00:00Z",
      },
      {
        id: "fallback-2",
        author_name: "Chocolate Manufacturer",
        author_title: "Processing Plant",
        author_country: "UAE",
        message: "We source Trinitario and Forastero lots through CHOCOCAM. Bean consistency and moisture control meet our production requirements every season.",
        rating: 5,
        up_votes: 6,
        down_votes: 0,
        created_at: "2025-12-02T00:00:00Z",
      },
      {
        id: "fallback-3",
        author_name: "Trading Partner",
        author_title: "Commodity Desk",
        author_country: "Netherlands",
        message: "Their team handles contract execution professionally, including customs documentation and container tracking until discharge.",
        rating: 5,
        up_votes: 7,
        down_votes: 0,
        created_at: "2025-11-19T00:00:00Z",
      },
      {
        id: "fallback-4",
        author_name: "Supply Director",
        author_title: "Industrial Buyer",
        author_country: "Canada",
        message: "Strong origin program with verified farmer partnerships. We appreciate their responsiveness and quality assurance discipline.",
        rating: 5,
        up_votes: 5,
        down_votes: 0,
        created_at: "2025-10-05T00:00:00Z",
      },
    ];
    if (slug === "criollo") {
      base[1].message = "Criollo lots meet our premium sensory requirements, and the shipment files are always complete.";
    }
    if (slug === "cundeamor") {
      base[2].message = "Specialty Cundeamor batches are consistent and work well for our premium chocolate formulations.";
    }
    if (slug === "amelonado") {
      base[3].message = "Amelonado availability is stable and lot traceability is clear from origin through dispatch.";
    }
    return base;
  }
  function testimonialCardHtml(item, index) {
    var avatar = TESTIMONIAL_IMAGES[index % TESTIMONIAL_IMAGES.length];
    var testimonialIdRaw = String(item.id || "");
    var id = escapeHtml(testimonialIdRaw || "testimonial-" + index);
    var authorName = escapeHtml(item.author_name || "Verified Buyer");
    var metaParts = [];
    if (item.author_title) metaParts.push(item.author_title);
    if (item.author_company) metaParts.push(item.author_company);
    if (item.author_country) metaParts.push(item.author_country);
    var meta = escapeHtml(metaParts.join(", "));
    var dateLabel = escapeHtml(formatDate(item.created_at));
    var message = escapeHtml(item.message || "");
    var upVotes = safeInt(item.up_votes);
    var downVotes = safeInt(item.down_votes);
    var canVote = isUuid(testimonialIdRaw) && ns.hasSupabaseConfig && ns.hasSupabaseConfig() && ns.catalogApi && ns.catalogApi.voteTestimonial;
    var voteDisabled = canVote ? "" : " disabled";
    var voteDisabledNote = canVote ? "" : " title=\"Voting is unavailable right now\"";
    return [
      '<article class="product-testimonial-card" data-testimonial-id="' + id + '">',
      ' <div class="product-testimonial-head">',
      '  <img class="img-circle product-testimonial-avatar" src="' + avatar + '" alt="Buyer testimonial avatar">',
      '  <div class="product-testimonial-meta">',
      '   <h5 class="product-testimonial-author">' + authorName + "</h5>",
      '   <h6 class="product-testimonial-subline">' + (meta || "Verified international buyer") + (dateLabel ? " <span>" + dateLabel + "</span>" : "") + "</h6>",
      '   <div class="product-testimonial-rating" aria-label="Buyer rating">' + starIcons(item.rating) + "</div>",
      "  </div>",
      " </div>",
      ' <p class="product-testimonial-message">' + message + "</p>",
      ' <div class="product-testimonial-actions">',
      '  <div class="product-testimonial-votes">',
      '   <button type="button" class="testimonial-vote-btn" data-vote="up" aria-label="Like testimonial"' + voteDisabled + voteDisabledNote + '><i class="fa fa-thumbs-up" aria-hidden="true"></i> <span class="vote-count-up">' + String(upVotes) + "</span></button>",
      '   <button type="button" class="testimonial-vote-btn" data-vote="down" aria-label="Dislike testimonial"' + voteDisabled + voteDisabledNote + '><i class="fa fa-thumbs-down" aria-hidden="true"></i> <span class="vote-count-down">' + String(downVotes) + "</span></button>",
      "  </div>",
      '  <button type="button" class="testimonial-reply-toggle" data-author-name="' + authorName + '">Reply</button>',
      " </div>",
      ' <p class="testimonial-vote-feedback" role="status" aria-live="polite"></p>',
      ' <form class="testimonial-reply-form" data-author-name="' + authorName + '" novalidate>',
      '  <h6 class="testimonial-reply-title">Reply to ' + authorName + "</h6>",
      '  <input type="text" name="replyName" class="form-control text_1_box testimonial-reply-input" placeholder="Your Name*" required>',
      '  <input type="email" name="replyEmail" class="form-control text_1_box testimonial-reply-input" placeholder="Work Email*" required>',
      '  <textarea name="replyMessage" class="form-control testimonial-reply-textarea" placeholder="Your reply message*" required></textarea>',
      '  <div class="testimonial-reply-buttons">',
      '   <button type="submit" class="testimonial-reply-submit">Send Reply</button>',
      '   <button type="button" class="testimonial-reply-cancel">Cancel</button>',
      "  </div>",
      '  <p class="testimonial-reply-feedback" role="status" aria-live="polite"></p>',
      " </form>",
      "</article>",
    ].join("");
  }
  function setCount(count) {
    var node = byId("product-testimonial-count");
    if (!node) return;
    node.textContent = String(Math.max(0, Number(count || 0)));
  }
  function renderTestimonials(items, fallbackNote) {
    var root = byId("product-testimonials");
    if (!root) return;
    var list = Array.isArray(items) ? items : [];
    setCount(list.length);
    if (!list.length) {
      root.innerHTML = '<p class="product-testimonials-empty">No published testimonials yet for this cocoa variety.</p>';
      return;
    }
    var infoLine = fallbackNote
      ? '<p class="product-testimonials-note">' + escapeHtml(fallbackNote) + "</p>"
      : "";
    var cards = list.map(function (item, index) {
      return testimonialCardHtml(item, index);
    }).join("");
    root.innerHTML = infoLine + cards;
  }
  function setReplyFeedback(form, message, isError) {
    if (!form) return;
    var feedback = form.querySelector(".testimonial-reply-feedback");
    if (!feedback) return;
    feedback.textContent = message || "";
    feedback.classList.remove("is-success", "is-error");
    if (message) {
      feedback.classList.add(isError ? "is-error" : "is-success");
    }
  }
  function setReplyBusy(form, busy) {
    if (!form) return;
    var submit = form.querySelector(".testimonial-reply-submit");
    if (!submit) return;
    if (busy) {
      submit.dataset.prevLabel = submit.textContent;
      submit.textContent = "Sending...";
      submit.disabled = true;
      return;
    }
    submit.textContent = submit.dataset.prevLabel || "Send Reply";
    submit.disabled = false;
  }
  function getVoteStorageKey(testimonialId) {
    return VOTE_STORAGE_PREFIX + testimonialId;
  }
  function getStoredVote(testimonialId) {
    if (!testimonialId) return "";
    try {
      return String(global.localStorage.getItem(getVoteStorageKey(testimonialId)) || "");
    } catch (error) {
      return "";
    }
  }
  function setStoredVote(testimonialId, voteType) {
    if (!testimonialId || (voteType !== "up" && voteType !== "down")) return;
    try {
      global.localStorage.setItem(getVoteStorageKey(testimonialId), voteType);
    } catch (error) {
    }
  }
  function setVoteFeedback(card, message, isError) {
    if (!card) return;
    var feedback = card.querySelector(".testimonial-vote-feedback");
    if (!feedback) return;
    feedback.textContent = message || "";
    feedback.classList.remove("is-success", "is-error");
    if (message) {
      feedback.classList.add(isError ? "is-error" : "is-success");
    }
  }
  function setVoteBusy(card, busy) {
    if (!card) return;
    card.classList.toggle("is-vote-busy", Boolean(busy));
    var buttons = card.querySelectorAll(".testimonial-vote-btn");
    buttons.forEach(function (button) {
      if (busy) {
        button.disabled = true;
      } else {
        var testimonialId = card.getAttribute("data-testimonial-id") || "";
        var localVote = getStoredVote(testimonialId);
        button.disabled = localVote === "up" || localVote === "down";
      }
    });
  }
  function updateVoteCounts(card, upVotes, downVotes) {
    if (!card) return;
    var upNode = card.querySelector(".vote-count-up");
    var downNode = card.querySelector(".vote-count-down");
    var currentUp = safeInt(upNode && upNode.textContent);
    var currentDown = safeInt(downNode && downNode.textContent);
    if (upNode) upNode.textContent = String(upVotes == null ? currentUp : safeInt(upVotes));
    if (downNode) downNode.textContent = String(downVotes == null ? currentDown : safeInt(downVotes));
  }
  function lockCardVote(card, voteType) {
    if (!card) return;
    var buttons = card.querySelectorAll(".testimonial-vote-btn");
    buttons.forEach(function (button) {
      var currentVote = (button.getAttribute("data-vote") || "").toLowerCase();
      button.classList.toggle("is-selected", currentVote === voteType);
      button.disabled = true;
    });
  }
  function applyStoredVotes() {
    var root = byId("product-testimonials");
    if (!root) return;
    var cards = root.querySelectorAll(".product-testimonial-card");
    cards.forEach(function (card) {
      var testimonialId = card.getAttribute("data-testimonial-id") || "";
      var voteType = getStoredVote(testimonialId);
      if (voteType === "up" || voteType === "down") {
        lockCardVote(card, voteType);
      }
    });
  }
  async function submitVote(card, voteType, productSlug) {
    if (!card || (voteType !== "up" && voteType !== "down")) return;
    var testimonialId = card.getAttribute("data-testimonial-id") || "";
    if (!isUuid(testimonialId)) {
      setVoteFeedback(card, "Voting is unavailable for this testimonial.", true);
      return;
    }
    var previousVote = getStoredVote(testimonialId);
    if (previousVote === "up" || previousVote === "down") {
      setVoteFeedback(card, "You already voted on this testimonial from this browser.", false);
      lockCardVote(card, previousVote);
      return;
    }
    if (!ns.hasSupabaseConfig || !ns.hasSupabaseConfig() || !ns.catalogApi || !ns.catalogApi.voteTestimonial) {
      setVoteFeedback(card, "Voting service is not configured yet.", true);
      return;
    }
    setVoteBusy(card, true);
    setVoteFeedback(card, "");
    try {
      var result = await ns.catalogApi.voteTestimonial({
        testimonialId: testimonialId,
        voteType: voteType,
        sourceChannel: "product_detail_testimonial",
        productSlug: productSlug || null,
      });
      updateVoteCounts(card, result && result.upVotes, result && result.downVotes);
      setStoredVote(testimonialId, voteType);
      lockCardVote(card, voteType);
      setVoteFeedback(card, "Thank you. Your feedback was recorded.", false);
    } catch (error) {
      var message = ns.resolveErrorMessage
        ? await ns.resolveErrorMessage(error, "Failed to submit vote")
        : ns.normalizeError
          ? ns.normalizeError(error, "Failed to submit vote")
          : "Failed to submit vote";
      setVoteFeedback(card, message, true);
    } finally {
      setVoteBusy(card, false);
    }
  }
  function closeAllReplyForms() {
    var root = byId("product-testimonials");
    if (!root) return;
    var forms = root.querySelectorAll(".testimonial-reply-form.is-open");
    forms.forEach(function (form) {
      form.classList.remove("is-open");
      setReplyFeedback(form, "");
    });
  }
  function openReplyForm(button) {
    var card = button.closest(".product-testimonial-card");
    if (!card) return;
    var form = card.querySelector(".testimonial-reply-form");
    if (!form) return;
    var wasOpen = form.classList.contains("is-open");
    closeAllReplyForms();
    if (wasOpen) {
      return;
    }
    form.classList.add("is-open");
    var nameInput = form.querySelector("input[name='replyName']");
    if (nameInput) {
      nameInput.focus();
    }
  }
  async function submitReply(form, productSlug) {
    var nameInput = form.querySelector("input[name='replyName']");
    var emailInput = form.querySelector("input[name='replyEmail']");
    var messageInput = form.querySelector("textarea[name='replyMessage']");
    var authorName = form.getAttribute("data-author-name") || "Buyer";
    var name = (nameInput && nameInput.value ? nameInput.value : "").trim();
    var email = (emailInput && emailInput.value ? emailInput.value : "").trim();
    var message = (messageInput && messageInput.value ? messageInput.value : "").trim();
    if (!name || !email || !message) {
      setReplyFeedback(form, "Please complete name, email, and message.", true);
      return;
    }
    if (!ns.hasSupabaseConfig || !ns.hasSupabaseConfig() || !ns.inquiryApi) {
      setReplyFeedback(form, "Reply service is not configured yet.", true);
      return;
    }
    var payload = {
      sourceChannel: "testimonial_reply",
      inquiryTopic: "Reply to Buyer Testimonial",
      productSlug: productSlug || null,
      contactName: name,
      companyName: name,
      workEmail: email,
      message: "Reply to " + authorName + ": " + message,
    };
    setReplyBusy(form, true);
    setReplyFeedback(form, "");
    try {
      await ns.inquiryApi.submitInquiry(payload);
      setReplyFeedback(form, "Reply sent successfully. Our export desk will follow up.", false);
      form.reset();
      setTimeout(function () {
        form.classList.remove("is-open");
        setReplyFeedback(form, "");
      }, 1400);
    } catch (error) {
      var msg = ns.resolveErrorMessage
        ? await ns.resolveErrorMessage(error, "Failed to send reply")
        : ns.normalizeError
          ? ns.normalizeError(error, "Failed to send reply")
          : "Failed to send reply";
      setReplyFeedback(form, msg, true);
    } finally {
      setReplyBusy(form, false);
    }
  }
  async function resolveTestimonialsForProduct(productSlug) {
    if (!ns.hasSupabaseConfig || !ns.hasSupabaseConfig() || !ns.catalogApi || !ns.catalogApi.listTestimonials) {
      return { items: getFallbackTestimonials(productSlug), note: "Displaying fallback testimonials." };
    }
    try {
      var productId = null;
      if (ns.catalogApi.getProductBySlug) {
        var product = await ns.catalogApi.getProductBySlug(productSlug);
        productId = product && product.id ? product.id : null;
      }
      var items = await ns.catalogApi.listTestimonials(productId);
      if (items && items.length) {
        return { items: items, note: "" };
      }
      return { items: getFallbackTestimonials(productSlug), note: "No published testimonials yet for this variety. Showing verified buyer feedback." };
    } catch (error) {
      return { items: getFallbackTestimonials(productSlug), note: "Could not load live testimonials right now. Showing verified buyer feedback." };
    }
  }
  async function init() {
    var root = byId("product-testimonials");
    if (!root) return;
    var activeProductSlug = getActiveProductSlug();
    var result = await resolveTestimonialsForProduct(activeProductSlug);
    renderTestimonials(result.items, result.note);
    applyStoredVotes();
    root.addEventListener("click", function (event) {
      var voteButton = event.target.closest(".testimonial-vote-btn");
      if (voteButton) {
        event.preventDefault();
        var card = voteButton.closest(".product-testimonial-card");
        var voteType = (voteButton.getAttribute("data-vote") || "").toLowerCase();
        if (card) {
          void submitVote(card, voteType, activeProductSlug);
        }
        return;
      }
      var toggle = event.target.closest(".testimonial-reply-toggle");
      if (toggle) {
        event.preventDefault();
        openReplyForm(toggle);
        return;
      }
      var cancel = event.target.closest(".testimonial-reply-cancel");
      if (cancel) {
        event.preventDefault();
        closeAllReplyForms();
      }
    });
    root.addEventListener("submit", function (event) {
      var form = event.target && event.target.closest ? event.target.closest(".testimonial-reply-form") : null;
      if (!form) return;
      event.preventDefault();
      void submitReply(form, activeProductSlug);
    });
  }
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () {
      void init();
    }, { once: true });
    return;
  }
  void init();
})(window);
